906	fn stage_preflight(
907	    root: &Path,
908	    state: &PushState,
909	    params: &PushParams,
910	) -> Result<(), Box<dyn std::error::Error>> {
911	    if params.dry_run {
912	        info!(
913	            "push preflight: [dry-run] would run verify-tracking / verify bot published / <self> sync --check"
914	        );
915	        return Ok(());
916	    }
917	    info!("push preflight: verify bookmark tracking");
918	    crate::common::verify_tracking(root, &state.bookmark)?;
919	    crate::common::verify_tracking(&claude_path(root), BOT_BOOKMARK)?;
920	    // Bot-repo published backstop (0.69.0-3): at rest `.claude
921	    // main` matches `main@origin`; a mismatch means an earlier
922	    // publish was lost. Errors — no automatic fixing.
923	    info!("push preflight: verify bot repo published ({BOT_BOOKMARK} == {BOT_BOOKMARK}@origin)");
924	    crate::common::verify_bot_published(&claude_path(root), BOT_BOOKMARK)?;
925	    // Re-invoke this binary by its own path rather than a
926	    // hard-coded name on PATH — keeps the shell-out correct across
927	    // any crate rename (e.g. the 0.69.0 `vc-x1-dev` window).
928	    // Inlining sync entirely is a Todo.
929	    let exe = std::env::current_exe()?;
930	    let exe_str = exe.to_string_lossy();
931	    info!("push preflight: {exe_str} sync --check");
932	    run(&exe_str, &["sync", "--check"], root)?;
933	    Ok(())
934	}
