936	/// Review: first approval gate — "is the work done right?".
937	///
938	/// Shows a `jj diff --stat` of the pending changes in both repos
939	/// and prompts the user to continue. `--yes` short-circuits the
940	/// prompt (required for scripted / non-tty use). In `--dry-run`
941	/// the diff is still shown (that's the point of dry-run — see
942	/// what *would* be reviewed) but approval is auto-granted.
943	fn stage_review(root: &Path, params: &PushParams) -> Result<(), Box<dyn std::error::Error>> {
944	    let claude = claude_path(root);
945	    let work_arg = root.to_string_lossy();
946	    let claude_arg = claude.to_string_lossy();
947	    info!("push review: pending changes:");
948	    info!("  work ({work_arg}):");
949	    let app_stat = run("jj", &["diff", "--stat", "-R", &work_arg], root)?;
950	    for line in app_stat.lines() {
951	        info!("    {line}");
952	    }
953	    info!("  .claude ({claude_arg}):");
954	    let claude_stat = run("jj", &["diff", "--stat", "-R", &claude_arg], root)?;
955	    for line in claude_stat.lines() {
956	        info!("    {line}");
957	    }
958	    if params.yes {
959	        info!("push review: auto-approved (--yes)");
960	        return Ok(());
961	    }
962	    if params.dry_run {
963	        info!("push review: [dry-run] auto-approved");
964	        return Ok(());
965	    }
966	    if !is_stdin_tty() {
967	        return Err("push review: stdin is not a tty; \
968	                    pass --yes to auto-approve in non-interactive contexts"
969	            .into());
970	    }
971	    let answer = prompt("push review: approve and continue to message stage? [y/N] ")?;
972	    let normalized = answer.trim().to_ascii_lowercase();
973	    if normalized == "y" || normalized == "yes" {
974	        Ok(())
975	    } else {
976	        Err(format!(
977	            "push review: declined (got {answer:?}); re-run with --yes or confirm with 'y'"
978	        )
979	        .into())
980	    }
981	}
982	
983	/// Message: collect pre-commit changeIDs and record whether
984	/// `.claude` has pending changes so `commit-bot` can skip when
985	/// empty. `--title` and `--body` are required in 0.37.0-2; `$EDITOR`
986	/// support + message persistence land in 0.37.0-3.
987	fn stage_message(
988	    root: &Path,
989	    state: &mut PushState,
990	    params: &PushParams,
991	    layout: &StateLayout,
992	) -> Result<(), Box<dyn std::error::Error>> {
993	    // Resolve title/body by priority:
994	    //   1. --title / --body flags (both must be present to skip editor)
995	    //   2. persisted title/body from prior stage run (resume case)
996	    //   3. $EDITOR template (interactive); fails if --yes and nothing else
997	    let (title, body) = match (params.title.clone(), params.body.clone()) {
998	        (Some(t), Some(b)) => (t, b),
999	        _ => match (state.title.clone(), state.body.clone()) {
1000	            (Some(t), Some(b)) => (t, b),
1001	            _ => {
1002	                if params.yes {
1003	                    return Err("push message: --yes given but --title/--body missing \
1004	                                and no persisted message to resume — pass both flags \
1005	                                or run interactively."
1006	                        .into());
1007	                }
1008	                if params.dry_run {
1009	                    return Err("push message: --dry-run given but --title/--body missing \
1010	                                and no persisted message — pass both flags so dry-run \
1011	                                has a message to preview."
1012	                        .into());
1013	                }
1014	                if !is_stdin_tty() {
1015	                    return Err("push message: stdin is not a tty and no --title/--body \
1016	                                supplied; cannot launch $EDITOR in a non-interactive \
1017	                                context. Pass --title and --body, or run interactively."
1018	                        .into());
1019	                }
1020	                compose_message_via_editor(layout)?
1021	            }
1022	        },
1023	    };
1024	
1025	    // Persist the composed message so a later resume (e.g. after a
1026	    // commit-work retry) doesn't need the flags re-passed.
1027	    state.title = Some(title.clone());
