//! Unit tests for the push module.

use super::*;
use clap::Parser;
use std::sync::atomic::{AtomicU64, Ordering};
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Parser)]
struct Cli {
    #[command(flatten)]
    args: PushArgs,
}

/// Per-test tempdir counter so file-system state doesn't collide
/// across parallel runs.
static COUNTER: AtomicU64 = AtomicU64::new(0);

/// Build a unique tempdir for a test and create it.
fn unique_tmp(tag: &str) -> PathBuf {
    let ts = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0); // OK: clock error → 0 is harmless for unique tempdir naming
    let n = COUNTER.fetch_add(1, Ordering::SeqCst);
    let path = std::env::temp_dir().join(format!("vc-x1-push-{tag}-{ts}-{n}"));
    fs::create_dir_all(&path).expect("create tempdir");
    path
}

/// Bare `push` with no flags leaves every optional field at its default.
---
1://! Integration tests for the push module.
2://!
3://! End-to-end tests for `push_in` against real dual-repo jj
4://! fixtures (bare-git remotes + colocated jj repos under a
5://! unique tempdir via `crate::test_helpers::Fixture`).
6://!
7://! Most tests use `--from message` to skip `preflight` — its
8://! `sync --check` step re-invokes `current_exe()`, which under
9://! `cargo test` is the test harness, not the CLI binary. Most
10://! also use `--no-squash-push`
11://! to focus on the earlier stages (message, commit-work,
12://! commit-bot, bookmark-set, push-work); the
13://! `push_squash_push_bot_*` tests run the in-process
14://! `squash-push-bot` stage for real. Everything is exercised
15://! against the fixture's local bare-git remotes.

