88	/// Run a command with retries, sleeping between attempts.
89	fn run_retry(
90	    cmd: &str,
91	    args: &[&str],
92	    cwd: &Path,
93	    retry: &PushRetryOptions,
94	) -> Result<String, Box<dyn std::error::Error>> {
95	    let mut last_err = String::new();
96	    for attempt in 1..=retry.push_retries {
97	        match run(cmd, args, cwd) {
98	            Ok(out) => {
99	                if attempt > 1 {
100	                    debug!("succeeded after {attempt} attempts");
101	                }
102	                return Ok(out);
103	            }
104	            Err(e) => {
105	                last_err = e.to_string();
106	                if attempt < retry.push_retries {
107	                    debug!(
108	                        "attempt {attempt}/{} failed: {last_err}",
109	                        retry.push_retries
110	                    );
111	                    debug!("retrying in {}s...", retry.push_retry_delay);
112	                    std::thread::sleep(std::time::Duration::from_secs(retry.push_retry_delay));
113	                }
114	            }
115	        }
116	    }
117	    Err(format!("failed after {} attempts: {last_err}", retry.push_retries).into())
118	}
