122	/// Parse the `--use-template` value into `(code, bot)` template paths.
123	///
124	/// Format: `CODE[,BOT]`. If `BOT` is omitted, the default is the sibling
125	/// directory whose name is `<CODE-basename>.claude` (via
126	/// `Path::with_file_name`, so a trailing slash on `CODE` does not produce
127	/// a different result).
128	pub(crate) fn parse_use_template(
129	    s: &str,
130	) -> Result<(PathBuf, PathBuf), Box<dyn std::error::Error>> {
131	    let mut parts = s.splitn(2, ',');
132	    let code_raw = parts.next().unwrap_or(""); // OK: splitn always yields at least one element
133	    let bot_raw = parts.next();
134	    let code_trim = code_raw.trim();
135	    if code_trim.is_empty() {
136	        return Err("--use-template: code template path is empty".into());
137	    }
138	    let code = PathBuf::from(code_trim);
139	    let bot = match bot_raw.map(str::trim) {
140	        Some(b) if !b.is_empty() => PathBuf::from(b),
141	        _ => {
142	            let file_name = code.file_name().ok_or_else(|| {
143	                format!(
144	                    "--use-template: cannot derive default bot path from '{}' (no file name component)",
145	                    code.display()
