33	///
34	/// Captures a repo's trailing working-copy writes into the last
35	/// commit and publishes it — rewriting an already-pushed commit is
36	/// a forced update. Zero-ceremony default: bare `vc-x1 squash-push`
37	/// squashes `@ → @-` and pushes `main` in `.`.
38	#[derive(Args, Debug)]
39	pub struct SquashPushArgs {
40	    /// Bookmark to advance and push
41	    #[arg(value_name = "BOOKMARK", default_value = "main")]
42	    pub bookmark: String,
43	
44	    /// Path to jj repo
45	    #[arg(short = 'R', long, default_value = ".")]
46	    pub repo: PathBuf,
