64	    /// proceeding. True for CLI invocations, which run at rest;
65	    /// `vc-x1 push`'s `squash-push-bot` stage sets false — there
66	    /// the mismatch is the normal mid-push state (`bookmark-set`
67	    /// just moved the bookmark, this stage publishes it), so the
68	    /// report would be a false alarm.
69	    pub report_publish_state: bool,
70	}
